export const getTakerStats = async ( options?: RequestInit): Promise<TakerStats> => {

  return customFetch<TakerStats>(getGetTakerStatsUrl(),
  {
    ...options,
    method: 'GET'


  }
);}





export const getGetTakerStatsQueryKey = () => {
    return [
    `/api/taker-stats`
    ] as const;
    }


export const getGetTakerStatsQueryOptions = <TData = Awaited<ReturnType<typeof getTakerStats>>, TError = ErrorType<void>>( options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getTakerStats>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getGetTakerStatsQueryKey();



    const queryFn: QueryFunction<Awaited<ReturnType<typeof getTakerStats>>> = ({ signal }) => getTakerStats({ signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof getTakerStats>>, TError, TData> & { queryKey: QueryKey }
}

export type GetTakerStatsQueryResult = NonNullable<Awaited<ReturnType<typeof getTakerStats>>>
export type GetTakerStatsQueryError = ErrorType<void>


/**
 * @summary My taker rebate tier and 7-day trading stats
 */

export function useGetTakerStats<TData = Awaited<ReturnType<typeof getTakerStats>>, TError = ErrorType<void>>(
  options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof getTakerStats>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getGetTakerStatsQueryOptions(options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







